func subscriptionStatusColor(status string) string {
	switch status {
	case "active":
		return "green"
	case "paused":
		return "yellow"
	case "cancelled":
		return "gray"
	default:
		return "gray"
	}
}

// subscriptionCycleLabel returns a display-friendly billing cycle label.
func subscriptionCycleLabel(cycle string) string {
	switch cycle {
	case "yearly":
		return "Yearly"
	default:
		return "Monthly"
	}
}

